import{_ as n,o as a,c as p,ae as l}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"03 - Concurrency 深度","description":"","frontmatter":{},"headers":[],"relativePath":"01-ios/02_Concurrency/03_Concurrency_Deep.md","filePath":"01-ios/02_Concurrency/03_Concurrency_Deep.md"}'),e={name:"01-ios/02_Concurrency/03_Concurrency_Deep.md"};function i(c,s,r,t,o,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="_03-concurrency-深度" tabindex="-1">03 - Concurrency 深度 <a class="header-anchor" href="#_03-concurrency-深度" aria-label="Permalink to &quot;03 - Concurrency 深度&quot;">​</a></h1><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ol><li><a href="#1-线程模型与调度策略">线程模型与调度策略</a></li><li><a href="#2-死锁产生条件与避免方案">死锁：产生条件与避免方案</a></li><li><a href="#3-内存屏障与原子操作">内存屏障与原子操作</a></li><li><a href="#4-并发设计模式">并发设计模式</a></li><li><a href="#5-面试题汇总">面试题汇总</a></li></ol><hr><h2 id="_1-线程模型与调度策略" tabindex="-1">1. 线程模型与调度策略 <a class="header-anchor" href="#_1-线程模型与调度策略" aria-label="Permalink to &quot;1. 线程模型与调度策略&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>iOS 线程模型：</span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  线程类型：                                                           │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  主线程（Main Thread）                                         │  │</span></span>
<span class="line"><span>│  │  • UI 更新唯一线程                                             │  │</span></span>
<span class="line"><span>│  │  • RunLoop 驱动事件循环                                       │  │</span></span>
<span class="line"><span>│  │  • 默认优先级（userInteractive）                               │  │</span></span>
<span class="line"><span>│  │  • 不能阻塞                                                   │  │</span></span>
<span class="line"><span>│  │  • 所有 UI 操作必须在此线程                                     │  │</span></span>
<span class="line"><span>│  │                                                                  │  │</span></span>
<span class="line"><span>│  │  后台线程（Background Thread）                                   │  │</span></span>
<span class="line"><span>│  │  • 网络请求、数据处理                                           │  │</span></span>
<span class="line"><span>│  │  • 优先级可配置（QoS）                                          │  │</span></span>
<span class="line"><span>│  │  • 数量受系统限制（约 64 个）                                  │  │</span></span>
<span class="line"><span>│  │  • 通过 DispatchQueue 创建                                      │  │</span></span>
<span class="line"><span>│  │                                                                  │  │</span></span>
<span class="line"><span>│  │  线程池（Thread Pool）                                            │  │</span></span>
<span class="line"><span>│  │  • GCD 自动管理线程池                                           │  │</span></span>
<span class="line"><span>│  │  • 自动线程复用                                                  │  │</span></span>
<span class="line"><span>│  │  • 线程数量根据负载动态调整                                     │  │</span></span>
<span class="line"><span>│  │  • 空闲线程会自动回收                                            │  │</span></span>
<span class="line"><span>│  └─────────────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  调度策略：                                                          │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  优先级抢占调度（Preemptive Scheduling）                         │  │</span></span>
<span class="line"><span>│  │  • 高优先级任务优先执行                                         │  │</span></span>
<span class="line"><span>│  │  • 低优先级任务可能被抢占                                       │  │</span></span>
<span class="line"><span>│  │  • iOS 系统使用 CFScheduler                                    │  │</span></span>
<span class="line"><span>│  │                                                                  │  │</span></span>
<span class="line"><span>│  │  时间片轮转调度（Round-Robin）                                    │  │</span></span>
<span class="line"><span>│  │  • 每个线程分配固定时间片                                       │  │</span></span>
<span class="line"><span>│  │  • 时间片用完 → 切换到下一个线程                                │  │</span></span>
<span class="line"><span>│  │  • 适用于同等优先级线程                                         │  │</span></span>
<span class="line"><span>│  │                                                                  │  │</span></span>
<span class="line"><span>│  │  实时调度（Real-Time Scheduling）                               │  │</span></span>
<span class="line"><span>│  │  • 最高优先级                                                   │  │</span></span>
<span class="line"><span>│  │  • 保证响应时间                                               │  │</span></span>
<span class="line"><span>│  │  • 仅用于系统关键任务                                           │  │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  QoS 映射：                                                          │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  UserInteractive → 最高优先级（保证 UI 流畅）                   │  │</span></span>
<span class="line"><span>│  │  UserInitiated → 高优先级（用户发起的任务）                      │  │</span></span>
<span class="line"><span>│  │  Default → 默认优先级（系统推荐）                               │  │</span></span>
<span class="line"><span>│  │  Utility → 低优先级（耗时任务）                                 │  │</span></span>
<span class="line"><span>│  │  Background → 最低优先级（后台刷新等）                          │  │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  线程性能分析：                                                     │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │  • 线程创建：约 1MB 内存（栈空间）                              │  │</span></span>
<span class="line"><span>│  │  • 线程切换：约 10-50μs                                      │  │</span></span>
<span class="line"><span>│  │  • GCD 线程池：复用现有线程（零创建开销）                      │  │</span></span>
<span class="line"><span>│  │  • async/await 协程：约 4KB 内存                              │  │</span></span>
<span class="line"><span>│  │  • 大量线程 → 内存压力/上下文切换开销                          │  │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────────┘  │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_2-死锁-产生条件与避免方案" tabindex="-1">2. 死锁：产生条件与避免方案 <a class="header-anchor" href="#_2-死锁-产生条件与避免方案" aria-label="Permalink to &quot;2. 死锁：产生条件与避免方案&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>死锁分析：</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  死锁的四个必要条件（Coffman Conditions）：                            │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  1. 互斥（Mutual Exclusion）— 资源只能被一个线程占用         │     │</span></span>
<span class="line"><span>│  │  2. 持有并等待（Hold and Wait）— 持有资源时等待其他资源       │     │</span></span>
<span class="line"><span>│  │  3. 不可抢占（No Preemption）— 资源不能被强制回收             │     │</span></span>
<span class="line"><span>│  │  4. 循环等待（Circular Wait）— 线程形成等待环                │     │</span></span>
<span class="line"><span>│  │                                                              │     │</span></span>
<span class="line"><span>│  │  死锁检测：                                                   │     │</span></span>
<span class="line"><span>│  │  • 资源分配图（Resource Allocation Graph）                   │     │</span></span>
<span class="line"><span>│  │  • 如果图中存在环 → 可能死锁                                 │     │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  常见的 iOS 死锁场景：                                              │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  场景 1：sync 到当前队列                                    │     │</span></span>
<span class="line"><span>│  │  ┌──────────────────────────────────────┐                 │     │</span></span>
<span class="line"><span>│  │  │  主线程：                              │                 │     │</span></span>
<span class="line"><span>│  │  │  1. 执行 sync 到主队列                 │                 │     │</span></span>
<span class="line"><span>│  │  │  2. 等待主队列任务完成                 │                 │     │</span></span>
<span class="line"><span>│  │  │  3. 主队列任务需要主线程执行            │                 │     │</span></span>
<span class="line"><span>│  │  │  4. 死锁！                           │                 │     │</span></span>
<span class="line"><span>│  │  └──────────────────────────────────────┘                 │     │</span></span>
<span class="line"><span>│  │                                                              │     │</span></span>
<span class="line"><span>│  │  场景 2：线程 A 锁 1 → 锁 2 / 线程 B 锁 2 → 锁 1            │     │</span></span>
<span class="line"><span>│  │  ┌──────────────────────────────────────┐                 │     │</span></span>
<span class="line"><span>│  │  │  Thread A: lock(1) → lock(2)           │                 │     │</span></span>
<span class="line"><span>│  │  │  Thread B: lock(2) → lock(1)           │                 │     │</span></span>
<span class="line"><span>│  │  │  → 互相等待 → 死锁                     │                 │     │</span></span>
<span class="line"><span>│  │  └──────────────────────────────────────┘                 │     │</span></span>
<span class="line"><span>│  │                                                              │     │</span></span>
<span class="line"><span>│  │  场景 3：DispatchGroup 等待超时                              │     │</span></span>
<span class="line"><span>│  │  ┌──────────────────────────────────────┐                 │     │</span></span>
<span class="line"><span>│  │  │  group.wait(timeout: .now() + 5)     │                 │     │</span></span>
<span class="line"><span>│  │  │  → 如果任务未 enter/leave 平衡        │                 │     │</span></span>
<span class="line"><span>│  │  │  → 永久等待 → 逻辑死锁                 │                 │     │</span></span>
<span class="line"><span>│  │  └──────────────────────────────────────┘                 │     │</span></span>
<span class="line"><span>│  │                                                              │     │</span></span>
<span class="line"><span>│  │  场景 4：主线程同步调用异步任务                              │     │</span></span>
<span class="line"><span>│  │  ┌──────────────────────────────────────┐                 │     │</span></span>
<span class="line"><span>│  │  │  主线程 sync 到主队列                 │                 │     │</span></span>
<span class="line"><span>│  │  │  或 async 到主队列 同步等待           │                 │     │</span></span>
<span class="line"><span>│  │  └──────────────────────────────────────┘                 │     │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  避免死锁的策略：                                                   │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  1. 始终使用 async 而非 sync                               │     │</span></span>
<span class="line"><span>│  │  2. 统一锁的顺序（所有线程按相同顺序获取锁）                  │     │</span></span>
<span class="line"><span>│  │  3. 使用 DispatchQueue 代替原生锁                         │     │</span></span>
<span class="line"><span>│  │  4. 使用 DispatchGroup 确保 enter/leave 平衡               │     │</span></span>
<span class="line"><span>│  │  5. 设置超时（group.wait(timeout:)）                        │     │</span></span>
<span class="line"><span>│  │  6. 使用 actor 隔离（避免手动锁）                          │     │</span></span>
<span class="line"><span>│  │  7. 使用 os_unfair_lock（可尝试获取，不会阻塞等待）         │     │</span></span>
<span class="line"><span>│  │  8. 避免嵌套锁                                              │     │</span></span>
<span class="line"><span>│  │  9. 使用 dispatch_semaphore 而非 manual lock               │     │</span></span>
<span class="line"><span>│  │  10. 使用 Thread Sanitizer 检测死锁                         │     │</span></span>
<span class="line"><span>│  │                                                              │     │</span></span>
<span class="line"><span>│  │  死锁检测工具：                                               │     │</span></span>
<span class="line"><span>│  │  • Thread Sanitizer（TSan）                                │     │</span></span>
<span class="line"><span>│  │  • Instruments → Thread Debugger                          │     │</span></span>
<span class="line"><span>│  │  • os_log 日志分析                                           │     │</span></span>
<span class="line"><span>│  │  • Xcode debugger                                            │     │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  ⚠️ 最佳实践：                                                     │</span></span>
<span class="line"><span>│  • 永远不要在主线程同步调用主队列任务                                │</span></span>
<span class="line"><span>│  • 使用 async/await 替代 sync                                     │</span></span>
<span class="line"><span>│  • 使用 actor 代替手动锁                                          │</span></span>
<span class="line"><span>│  • 使用 DispatchGroup + timeout 防止永久等待                        │</span></span>
<span class="line"><span>│  • 所有锁必须成对获取/释放（使用 defer）                            │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_3-内存屏障与原子操作" tabindex="-1">3. 内存屏障与原子操作 <a class="header-anchor" href="#_3-内存屏障与原子操作" aria-label="Permalink to &quot;3. 内存屏障与原子操作&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>内存屏障与原子操作：</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  内存屏障（Memory Barrier）：                                      │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  • 保证内存操作的顺序性                                   │     │</span></span>
<span class="line"><span>│  │  • 防止编译器/CPU 重排序                                  │     │</span></span>
<span class="line"><span>│  │  • 在多核 CPU 中至关重要                                   │     │</span></span>
<span class="line"><span>│  │  • iOS 中使用 os_atomic_* API                            │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  内存屏障类型：                                           │     │</span></span>
<span class="line"><span>│  │  • acquire（获取）— 屏障后的读不能重排序到屏障前           │     │</span></span>
<span class="line"><span>│  │  • release（释放）— 屏障前的写不能重排序到屏障后           │     │</span></span>
<span class="line"><span>│  │  • acquire-release — 组合屏障                             │     │</span></span>
<span class="line"><span>│  │  • seq_cst（顺序一致性）— 最强的内存屏障                   │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  使用场景：                                                │     │</span></span>
<span class="line"><span>│  │  • 多线程共享变量的读写                                    │     │</span></span>
<span class="line"><span>│  │  • 实现无锁数据结构                                         │     │</span></span>
<span class="line"><span>│  │  • 实现同步原语（如 spin lock）                           │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  原子操作（Atomic Operations）：                                    │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  • 不可分割的操作（要么全部执行，要么不执行）                │     │</span></span>
<span class="line"><span>│  │  • 不需要锁                                                  │     │</span></span>
<span class="line"><span>│  │  • 比锁更高效                                                  │     │</span></span>
<span class="line"><span>│  │  • iOS 使用 os_unfair_lock 和 os_atomic_* API              │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  os_unfair_lock（推荐 ✅）                                   │     │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────┐    │     │</span></span>
<span class="line"><span>│  │  │  let lock = os_unfair_lock()                       │    │     │</span></span>
<span class="line"><span>│  │  │  os_unfair_lock_lock(&amp;lock)                        │    │     │</span></span>
<span class="line"><span>│  │  │  // 临界区                                          │    │     │</span></span>
<span class="line"><span>│  │  │  os_unfair_lock_unlock(&amp;lock)                      │    │     │</span></span>
<span class="line"><span>│  │  │                                                   │    │     │</span></span>
<span class="line"><span>│  │  │  // 与 NSLock 对比                                │    │     │</span></span>
<span class="line"><span>│  │  │  • os_unfair_lock：C API，更高效                    │    │     │</span></span>
<span class="line"><span>│  │  │  • NSLock：ObjC 封装，更易用                        │    │     │</span></span>
<span class="line"><span>│  │  │  • 性能：os_unfair_lock &gt; NSLock                   │    │     │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────┘    │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  os_atomic（原子操作 API）                               │     │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────┐    │     │</span></span>
<span class="line"><span>│  │  │  os_atomic_increment(&amp;counter, memory_order_relaxed)  │</span></span>
<span class="line"><span>│  │  │  os_atomic_decrement(&amp;counter, memory_order_relaxed)  │</span></span>
<span class="line"><span>│  │  │  os_atomic_load(&amp;var, memory_order_relaxed)        │    │     │</span></span>
<span class="line"><span>│  │  │  os_atomic_store(&amp;var, newValue, memory_order_relaxed)  │</span></span>
<span class="line"><span>│  │  │                                                   │    │     │</span></span>
<span class="line"><span>│  │  │  memory_order 类型：                              │    │     │</span></span>
<span class="line"><span>│  │  │  • relaxed：无顺序保证（最高性能）                 │    │     │</span></span>
<span class="line"><span>│  │  │  • acquire：获取语义                               │    │     │</span></span>
<span class="line"><span>│  │  │  • release：释放语义                               │    │     │</span></span>
<span class="line"><span>│  │  │  • acquire-release：组合                           │    │     │</span></span>
<span class="line"><span>│  │  │  • seq_cst：顺序一致（最强）                       │    │     │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────┘    │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  无锁编程（Lock-Free Programming）：                                │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  优点：                                                   │     │</span></span>
<span class="line"><span>│  │  • 无锁竞争 → 更高性能                                    │     │</span></span>
<span class="line"><span>│  │  • 不会死锁                                              │     │</span></span>
<span class="line"><span>│  │  • 线程安全                                               │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  缺点：                                                   │     │</span></span>
<span class="line"><span>│  │  • 实现复杂                                                │     │</span></span>
<span class="line"><span>│  │  • 容易引入微妙 bug                                        │     │</span></span>
<span class="line"><span>│  │  • 不适合所有场景                                          │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  CAS（Compare-And-Swap）原子操作：                       │     │</span></span>
<span class="line"><span>│  │  ┌───────────────────────────────────────────────────┐    │     │</span></span>
<span class="line"><span>│  │  │  1. 读取旧值                                       │    │     │</span></span>
<span class="line"><span>│  │  │  2. 比较旧值与期望值                                │    │     │</span></span>
<span class="line"><span>│  │  │  3. 相等 → 更新为新值                              │    │     │</span></span>
<span class="line"><span>│  │  │  4. 不等 → 重试                                    │    │     │</span></span>
<span class="line"><span>│  │  │                                                   │    │     │</span></span>
<span class="line"><span>│  │  │  应用场景：                                       │    │     │</span></span>
<span class="line"><span>│  │  │  • 无锁队列                                       │    │     │</span></span>
<span class="line"><span>│  │  │  • 引用计数                                      │    │     │</span></span>
<span class="line"><span>│  │  │  • 计数器                                         │    │     │</span></span>
<span class="line"><span>│  │  └───────────────────────────────────────────────────┘    │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  性能分析：                                                       │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  • NSLock：约 100-200ns                                │     │</span></span>
<span class="line"><span>│  │  • os_unfair_lock：约 50-100ns                         │     │</span></span>
<span class="line"><span>│  │  • os_atomic：约 10-50ns                              │     │</span></span>
<span class="line"><span>│  │  • CAS：约 10-30ns                                   │     │</span></span>
<span class="line"><span>│  │  • 锁 vs 原子操作：原子操作更快（无内核调用）           │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_4-并发设计模式" tabindex="-1">4. 并发设计模式 <a class="header-anchor" href="#_4-并发设计模式" aria-label="Permalink to &quot;4. 并发设计模式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>并发设计模式：</span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  1. 生产者-消费者模式                                               │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  actor Queue {                                            │     │</span></span>
<span class="line"><span>│  │      private var items: [Data] = []                      │     │</span></span>
<span class="line"><span>│  │      private let maxItems = 100                          │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func enqueue(item: Data) async {                   │     │</span></span>
<span class="line"><span>│  │          while items.count &gt;= maxItems {                 │     │</span></span>
<span class="line"><span>│  │              await Task.yield()  // 等待空间            │     │</span></span>
<span class="line"><span>│  │          }                                                │     │</span></span>
<span class="line"><span>│  │          items.append(item)                               │     │</span></span>
<span class="line"><span>│  │      }                                                   │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func dequeue() async -&gt; Data? {                    │     │</span></span>
<span class="line"><span>│  │          guard !items.isEmpty else {                      │     │</span></span>
<span class="line"><span>│  │              await Task.yield()  // 等待数据            │     │</span></span>
<span class="line"><span>│  │              return items.isEmpty ? nil : dequeue()       │     │</span></span>
<span class="line"><span>│  │          }                                                │     │</span></span>
<span class="line"><span>│  │          return items.removeFirst()                       │     │</span></span>
<span class="line"><span>│  │      }                                                   │     │</span></span>
<span class="line"><span>│  │  }                                                        │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │  使用：                                                   │     │</span></span>
<span class="line"><span>│  │  Task { for item in source { await queue.enqueue(item: item) } }  │</span></span>
<span class="line"><span>│  │  Task { while let data = await queue.dequeue() { process(data) } }  │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  2. 工作线程池模式                                                  │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  actor ThreadPool {                                        │     │</span></span>
<span class="line"><span>│  │      private var workers: [Int: Task&lt;Void, Never&gt;] = []   │     │</span></span>
<span class="line"><span>│  │      private var taskQueue: [() async -&gt; Void] = []        │     │</span></span>
<span class="line"><span>│  │      private let maxWorkers = 8                            │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func submit(work: @escaping () async -&gt; Void) {      │     │</span></span>
<span class="line"><span>│  │          if workers.count &lt; maxWorkers {                   │     │</span></span>
<span class="line"><span>│  │              let worker = Task {                           │     │</span></span>
<span class="line"><span>│  │                  while let task = taskQueue.first {        │     │</span></span>
<span class="line"><span>│  │                      taskQueue.removeFirst()                │     │</span></span>
<span class="line"><span>│  │                      await task()                           │     │</span></span>
<span class="line"><span>│  │                  }                                         │     │</span></span>
<span class="line"><span>│  │              }                                              │     │</span></span>
<span class="line"><span>│  │              workers[worker.hashValue] = worker             │     │</span></span>
<span class="line"><span>│  │          } else {                                           │     │</span></span>
<span class="line"><span>│  │              taskQueue.append(work)                         │     │</span></span>
<span class="line"><span>│  │          }                                                  │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │  }                                                          │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  3. Future/Promise 模式                                              │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  class Promise&lt;T&gt; {                                        │     │</span></span>
<span class="line"><span>│  │      private var continuation: CheckedContinuation&lt;T, Error&gt;?  │</span></span>
<span class="line"><span>│  │      private var value: Result&lt;T, Error&gt;?                  │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func then(_ handler: @escaping (T) async throws -&gt; R) -&gt; Promise&lt;R&gt; {  │</span></span>
<span class="line"><span>│  │          return Promise&lt;R&gt; { resolver in                   │     │</span></span>
<span class="line"><span>│  │              let result = try await value.get()             │     │</span></span>
<span class="line"><span>│  │              let newValue = try await handler(result)       │     │</span></span>
<span class="line"><span>│  │              resolver.fulfill(newValue)                     │     │</span></span>
<span class="line"><span>│  │          }                                                  │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │  }                                                          │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  4. Barrier（屏障）模式                                               │</span></span>
<span class="line"><span>│  ┌────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  actor SharedData {                                          │     │</span></span>
<span class="line"><span>│  │      private var data: [String: Data] = [:]                 │     │</span></span>
<span class="line"><span>│  │      private var isReady = false                            │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func write(key: String, value: Data) async {         │     │</span></span>
<span class="line"><span>│  │          data[key] = value                                  │     │</span></span>
<span class="line"><span>│  │          if data.count &gt;= threshold { isReady = true }     │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func waitForAll() async -&gt; [String: Data]? {         │     │</span></span>
<span class="line"><span>│  │          guard isReady else {                              │     │</span></span>
<span class="line"><span>│  │              await Task.yield()                             │     │</span></span>
<span class="line"><span>│  │              return data.count &gt;= threshold ? data : nil    │     │</span></span>
<span class="line"><span>│  │          }                                                  │     │</span></span>
<span class="line"><span>│  │          return data                                        │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │  }                                                          │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  5. Observer（观察者）模式                                         │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  actor EventEmitter {                                   │     │</span></span>
<span class="line"><span>│  │      private var listeners: [(Event) -&gt; Void] = []      │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func subscribe(listener: @escaping (Event) -&gt; Void) {  │</span></span>
<span class="line"><span>│  │          listeners.append(listener)                       │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │                                                            │     │</span></span>
<span class="line"><span>│  │      func publish(event: Event) async {                  │     │</span></span>
<span class="line"><span>│  │          for listener in listeners {                       │     │</span></span>
<span class="line"><span>│  │              await listener(event)                         │     │</span></span>
<span class="line"><span>│  │          }                                                  │     │</span></span>
<span class="line"><span>│  │      }                                                     │     │</span></span>
<span class="line"><span>│  │  }                                                          │     │</span></span>
<span class="line"><span>│  └────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>│  模式选择指南：                                                     │</span></span>
<span class="line"><span>│  ┌──────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│  │  场景                    │ 推荐模式                        │   │</span></span>
<span class="line"><span>│  │  ────                    │ ──────                          │   │</span></span>
<span class="line"><span>│  │  大量并发数据流           │ 生产者-消费者                    │   │</span></span>
<span class="line"><span>│  │  固定数量线程池          │ 工作线程池                      │   │</span></span>
<span class="line"><span>│  │  异步操作链               │ Future/Promise                 │   │</span></span>
<span class="line"><span>│  │  等待多个任务完成         │ Barrier                        │   │</span></span>
<span class="line"><span>│  │  事件通知                 │ Observer                       │   │</span></span>
<span class="line"><span>│  │  共享状态                 │ Actor                          │   │</span></span>
<span class="line"><span>│  └──────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>*/</span></span></code></pre></div><hr><h2 id="_5-面试题汇总" tabindex="-1">5. 面试题汇总 <a class="header-anchor" href="#_5-面试题汇总" aria-label="Permalink to &quot;5. 面试题汇总&quot;">​</a></h2><h3 id="高频面试题" tabindex="-1">高频面试题 <a class="header-anchor" href="#高频面试题" aria-label="Permalink to &quot;高频面试题&quot;">​</a></h3><p><strong>Q1: 死锁的四个必要条件？</strong></p><p><strong>答</strong>：互斥、持有并等待、不可抢占、循环等待。避免任一条件即可打破死锁。</p><p><strong>Q2: iOS 线程模型？</strong></p><p><strong>答</strong>：主线程（UI）、后台线程（网络/数据处理）、线程池（GCD 自动管理）。QoS 决定优先级。</p><p><strong>Q3: 内存屏障的作用？</strong></p><p><strong>答</strong>：保证内存操作的顺序性，防止重排序。acquire/release/seq_cst 四种语义。</p><p><strong>Q4: 原子操作 vs 锁？</strong></p><p><strong>答</strong>：原子操作更快（无内核调用），不需要锁。OS_unfair_lock &gt; NSLock &gt; 原子操作（CAS）。</p><p><strong>Q5: 并发设计模式？</strong></p><p><strong>答</strong>：生产者-消费者、工作线程池、Future/Promise、Barrier、Observer。根据场景选择。</p><hr><h2 id="_6-参考资源" tabindex="-1">6. 参考资源 <a class="header-anchor" href="#_6-参考资源" aria-label="Permalink to &quot;6. 参考资源&quot;">​</a></h2><ul><li><a href="https://developer.apple.com/documentation/os/os_unfair_lock" target="_blank" rel="noreferrer">Apple: os_unfair_lock</a></li><li><a href="https://developer.apple.com/documentation/os/os_atomic" target="_blank" rel="noreferrer">Apple: os_atomic</a></li><li><a href="https://developer.apple.com/documentation/dispatch" target="_blank" rel="noreferrer">Apple: Dispatch</a></li><li><a href="https://developer.apple.com/documentation/os" target="_blank" rel="noreferrer">Apple: OS Framework Reference</a></li><li><a href="https://en.wikipedia.org/wiki/Deadlock" target="_blank" rel="noreferrer">Coffman Conditions</a></li><li><a href="https://nshipster.com/dispatch" target="_blank" rel="noreferrer">NSHipster: Dispatch</a></li></ul>`,31)])])}const _=n(e,[["render",i]]);export{h as __pageData,_ as default};
